import { mkdir, mkdtemp, readFile, rm } from "node:fs/promises";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { afterEach, describe, expect } from "bun:test";
import { Session } from "../src/session/session.js";
import { applyInlineSlashCommands } from "../src/tui/slash-commands.js";
import { testIfDocker } from "./helpers/docker-only.js";

let tempDirs: string[] = [];

afterEach(async () => {
  for (const tempDir of tempDirs) {
    await rm(tempDir, { recursive: true, force: true });
  }
  tempDirs = [];
});

describe("Session model-switch persistence", () => {
  // Resume must let a new --model override the previously persisted state.options.model.
  // Without that override, sessions would silently keep running on whatever model was used
  // at first start, regardless of the user's current CLI flag.
  testIfDocker(
    "resume with a new --model overwrites state.options.model in state.json",
    async () => {
      const tempDir = await mkdtemp(join(tmpdir(), "duet-model-switch-"));
      tempDirs.push(tempDir);
      const sessionPath = join(tempDir, "switch-session");
      await mkdir(sessionPath, { recursive: true });

      // First session: persist state with model A.
      const first = new Session(
        {
          model: "anthropic:claude-opus-4-7",
          memoryDbPath: false,
          skillDiscovery: { includeDefaults: false },
        },
        { id: "switch-session", sessionPath },
      );
      await first.start();
      await first.dispose();

      const stateAfterFirst = JSON.parse(await readFile(join(sessionPath, "state.json"), "utf-8"));
      expect(stateAfterFirst.state.options.model).toBe("anthropic:claude-opus-4-7");

      // Resume the same session path with model B.
      const second = new Session(
        {
          model: "anthropic:claude-sonnet-5-1",
          memoryDbPath: false,
          skillDiscovery: { includeDefaults: false },
        },
        { id: "switch-session", sessionPath, resumeFromStorage: true },
      );
      await second.start();
      await second.dispose();

      const stateAfterSecond = JSON.parse(await readFile(join(sessionPath, "state.json"), "utf-8"));
      expect(stateAfterSecond.state.options.model).toBe("anthropic:claude-sonnet-5-1");
    },
  );

  // setModel() lets the TUI's /model slash command swap the model used for
  // subsequent turns. The change is config-level only — it must take effect
  // on the next prompt without touching any in-flight turn.
  testIfDocker("setModel mutates config.model and is picked up on next start", async () => {
    const tempDir = await mkdtemp(join(tmpdir(), "duet-model-set-"));
    tempDirs.push(tempDir);
    const sessionPath = join(tempDir, "set-session");
    await mkdir(sessionPath, { recursive: true });

    const session = new Session(
      {
        model: "anthropic:claude-opus-4-7",
        memoryDbPath: false,
        skillDiscovery: { includeDefaults: false },
      },
      { id: "set-session", sessionPath },
    );

    const result = session.setModel("anthropic:claude-sonnet-5-1");
    expect(result.modelName).toBe("anthropic:claude-sonnet-5-1");
    expect(session.config.model).toBe("anthropic:claude-sonnet-5-1");

    await session.start();
    await session.dispose();

    const stored = JSON.parse(await readFile(join(sessionPath, "state.json"), "utf-8"));
    expect(stored.state.options.model).toBe("anthropic:claude-sonnet-5-1");
  });

  testIfDocker(
    "setThinkingLevel mutates config.thinkingLevel and is picked up on next start",
    async () => {
      const tempDir = await mkdtemp(join(tmpdir(), "duet-thinking-set-"));
      tempDirs.push(tempDir);
      const sessionPath = join(tempDir, "thinking-session");
      await mkdir(sessionPath, { recursive: true });

      const session = new Session(
        {
          model: "anthropic:claude-opus-4-7",
          thinkingLevel: "medium",
          memoryDbPath: false,
          skillDiscovery: { includeDefaults: false },
        },
        { id: "thinking-session", sessionPath },
      );

      const result = session.setThinkingLevel("HIGH");
      expect(result.thinkingLevel).toBe("high");
      expect(session.config.thinkingLevel).toBe("high");

      await session.start();
      await session.dispose();

      const stored = JSON.parse(await readFile(join(sessionPath, "state.json"), "utf-8"));
      expect(stored.state.options.thinkingLevel).toBe("high");
    },
  );

import { describe, expect, test, spyOn } from "bun:test";
import { homedir } from "node:os";
import { join } from "node:path";
import { driveRpcLoop, parseRpcArgs, parseRpcCommandLine, type RpcRunner } from "../src/cli/rpc.js";
import type {
  TurnCompactCommand,
  TurnEditFollowUpQueueCommand,
  TurnInterruptCommand,
  TurnRunnerCommand,
  TurnSystemEvent,
  TurnTerminalEvent,
} from "../src/types/protocol.js";

/**
 * Async iterable helper for `driveRpcLoop`. Pulling from an array makes the
 * loop's phase transitions easy to assert: each yielded value is a single
 * stdin line the loop would have read.
 */
function commandStream(commands: TurnRunnerCommand[]): AsyncIterable<TurnRunnerCommand> {
  return (async function* () {
    for (const command of commands) yield command;
  })();
}

interface RecordedRunner extends RpcRunner {
  starts: Array<Extract<TurnRunnerCommand, { type: "start" }>>;
  turns: Array<Extract<TurnRunnerCommand, { type: "prompt" | "answer" | "wake" }>>;
  interrupts: TurnInterruptCommand[];
  editQueues: TurnEditFollowUpQueueCommand[];
  compacts: TurnCompactCommand[];
  resolveTurn: (terminal: TurnTerminalEvent) => void;
}

/**
 * Capture the {@link TurnSystemEvent}s the dispatch loop emits for soft
 * protocol errors (malformed commands, premature commands before start,
 * unknown command types). Used in lieu of the older fatal-exit assertions.
 */
function buildEventSink(): {
  emit: (event: TurnSystemEvent) => void;
  events: TurnSystemEvent[];
} {
  const events: TurnSystemEvent[] = [];
  return { events, emit: (event) => events.push(event) };
}

/**
 * In-memory {@link RpcRunner} that records dispatched commands and exposes a
 * `resolveTurn` hook so tests can decide when the in-flight turn settles. This
 * lets us assert that mid-turn commands reach the runner before the terminal
 * event.
 */
function buildRunner(): RecordedRunner {
  let resolveTurn!: (terminal: TurnTerminalEvent) => void;
  const turnPromise = new Promise<TurnTerminalEvent>((resolve) => {
    resolveTurn = resolve;
  });
  const runner: RecordedRunner = {
    starts: [],
    turns: [],
    interrupts: [],
    editQueues: [],
    compacts: [],
    resolveTurn,
    async start(command) {
      runner.starts.push(command);
    },
    async turn(command) {
      runner.turns.push(command);
      return turnPromise;
    },
    interrupt(command) {
      runner.interrupts.push(command);
    },
    editFollowUpQueue(command) {
      runner.editQueues.push(command);
    },
    compact(command) {
      runner.compacts.push(command);
    },
  };
  return runner;
}

describe("parseRpcArgs", () => {
  test("collects supported flags and defaults workDir to cwd", () => {
    const parsed = parseRpcArgs([
      "--rpc",
      "--model",
      "opus-4.7",
      "--memory-model",
      "haiku-4.5",
      "--workdir",
      "/tmp/repo",
      "--system-prompt",
      "be brief",
      "--system-prompt-file",
      "A.md",
      "--system-prompt-file",
      "B.md",
      "--env-file",
      "/etc/duet/env",
      "-i",
    ]);
    expect(parsed.modelName).toBe("opus-4.7");
    expect(parsed.memoryModelName).toBe("haiku-4.5");
    expect(parsed.workDir).toBe("/tmp/repo");
    expect(parsed.systemInstructions).toBe("be brief");
    expect(parsed.systemPromptFiles).toEqual(["A.md", "B.md"]);
    expect(parsed.envFilePath).toBe("/etc/duet/env");
    expect(parsed.incognito).toBe(true);
    expect(parsed.noSkillSync).toBe(false);
  });

  test("expands a leading ~ in --workdir to the user's home directory", () => {
    const home = homedir();
    expect(parseRpcArgs(["--workdir", "~/code/foo"]).workDir).toBe(join(home, "code/foo"));
    expect(parseRpcArgs(["-w", "~"]).workDir).toBe(home);
    // Non-tilde paths pass through unchanged so relative workdirs still
    // resolve against the spawning shell's cwd.
    expect(parseRpcArgs(["--workdir", "/abs/path"]).workDir).toBe("/abs/path");
    expect(parseRpcArgs(["--workdir", "relative/path"]).workDir).toBe("relative/path");
  });

  test("--db sets an explicit memory database path", () => {
    const parsed = parseRpcArgs(["--db", "/tmp/custom.db"]);
    expect(parsed.dbPath).toBe("/tmp/custom.db");
  });

  test("omitting --db leaves dbPath undefined so the default applies", () => {
    const parsed = parseRpcArgs([]);
    expect(parsed.dbPath).toBeUndefined();
  });

  test("--no-skill-sync sets the skip-skill-sync flag", () => {
    const parsed = parseRpcArgs(["--no-skill-sync"]);
    expect(parsed.noSkillSync).toBe(true);
  });

  test("--no-auto-upgrade is accepted as a no-op", () => {
    // RPC mode never auto-upgrades; the flag is tolerated for host scripts
    // that forward run-mode flags into `--rpc` invocations.
    expect(() => parseRpcArgs(["--no-auto-upgrade"])).not.toThrow();
  });

  test("--no-system-prompt-files resets the system prompt file list", () => {
    const parsed = parseRpcArgs(["--system-prompt-file", "A.md", "--no-system-prompt-files"]);
    expect(parsed.systemPromptFiles).toEqual([]);
  });

  test("--provider pins the catalog defaults and rejects --model overlap", () => {
    const ok = parseRpcArgs(["--provider", "openai"]);
    expect(ok.modelName).toBeDefined();
    expect(ok.memoryModelName).toBeDefined();

    const exitSpy = stubProcessExit();
    try {
      expect(() => parseRpcArgs(["--provider", "openai", "--model", "gpt-5.5"])).toThrow();
    } finally {
      exitSpy.mockRestore();
    }
  });

  test("rejects positional arguments because RPC reads commands from stdin", () => {
    const exitSpy = stubProcessExit();
    try {
      expect(() => parseRpcArgs(["stray"])).toThrow();
    } finally {
      exitSpy.mockRestore();
    }
  });

  test("rejects unknown flags", () => {
    const exitSpy = stubProcessExit();
    try {
      expect(() => parseRpcArgs(["--bogus"])).toThrow();
    } finally {
      exitSpy.mockRestore();
    }
  });
});

/**
 * Replace `process.exit` with a throwing stub for the duration of one test.
 * `fail()` calls `process.exit(1)`, which would terminate the test runner;
 * the stub turns that into a regular thrown error the test can assert on.
 */
function stubProcessExit() {
  return spyOn(process, "exit").mockImplementation((() => {
    throw new Error("exit");
  }) as never);
}

describe("parseRpcCommandLine", () => {
  test("returns a skip result for blank/whitespace lines so the iterator can skip them", () => {
    expect(parseRpcCommandLine("")).toEqual({ kind: "skip" });
    expect(parseRpcCommandLine("   \t  ")).toEqual({ kind: "skip" });
  });

  test("parses a well-formed JSON command", () => {
    expect(parseRpcCommandLine('{"type":"start"}')).toEqual({
      kind: "command",
      command: { type: "start" },
    });
  });

  test("reports malformed JSON as an error result instead of exiting", () => {
    const result = parseRpcCommandLine("{not json");
    expect(result.kind).toBe("error");
    if (result.kind !== "error") throw new Error("unreachable");
    expect(result.message).toMatch(/Invalid RPC command JSON/);
  });

  test("reports JSON without a string `type` field as an error result", () => {
    const missingType = parseRpcCommandLine('{"foo":"bar"}');
    expect(missingType.kind).toBe("error");
    const plainString = parseRpcCommandLine('"plain string"');
    expect(plainString.kind).toBe("error");
  });
});
import { describe, expect, test } from "bun:test";
import { applyInlineSlashCommandsToCliConfig } from "../src/cli/inline-slash.js";
import type { TurnRunnerConfig } from "../src/types/config.js";

function makeConfig(overrides: Partial<TurnRunnerConfig> = {}): TurnRunnerConfig {
  return {
    model: "anthropic:claude-opus-4-7",
    memoryDbPath: false,
    skillDiscovery: { includeDefaults: false },
    ...overrides,
  } as TurnRunnerConfig;
}

function makeLog(): { lines: string[]; write: (line: string) => void } {
  const lines: string[] = [];
  return { lines, write: (line) => lines.push(line) };
}

describe("applyInlineSlashCommandsToCliConfig", () => {
  test("inline /model with a valid provider-pinned name mutates config and strips it from residue", () => {
    const config = makeConfig();
    const log = makeLog();

    const { residue } = applyInlineSlashCommandsToCliConfig(
      "hey can you review this /model anthropic:claude-sonnet-5-1",
      config,
      log.write,
    );

    expect(config.model).toBe("anthropic:claude-sonnet-5-1");
    expect(log.lines.join("")).toContain("[model] next turn will use anthropic:claude-sonnet-5-1");
    expect(residue).toBe("hey can you review this");
  });

  test("whole-prompt /model returns an empty residue so the CLI can skip the agent turn", () => {
    // This is the `duet "/model X"` case: the whole prompt is just a
    // slash command. The CLI mutates config and returns "" so run.ts
    // unsets `prompt` and never dispatches an agent turn.
    const config = makeConfig();
    const log = makeLog();

    const { residue } = applyInlineSlashCommandsToCliConfig(
      "/model anthropic:claude-sonnet-5-1",
      config,
      log.write,
    );

    expect(config.model).toBe("anthropic:claude-sonnet-5-1");
    expect(residue).toBe("");
  });

  test("whole-prompt /model X /thinking Y applies both swaps and still returns empty residue", () => {
    const config = makeConfig({ thinkingLevel: "medium" });
    const log = makeLog();

    const { residue } = applyInlineSlashCommandsToCliConfig(
      "/model anthropic:claude-sonnet-5-1 /thinking high",
      config,
      log.write,
    );

    expect(config.model).toBe("anthropic:claude-sonnet-5-1");
    expect(config.thinkingLevel).toBe("high");
    expect(residue).toBe("");
  });

  test("inline /thinking with a valid level mutates config and confirms via log", () => {
    const config = makeConfig({ thinkingLevel: "medium" });
    const log = makeLog();

    const { residue } = applyInlineSlashCommandsToCliConfig(
      "please /thinking high and reply",
      config,
      log.write,
    );

    expect(config.thinkingLevel).toBe("high");
    expect(log.lines.join("")).toContain("[thinking] next turn will think at high");
    expect(residue).toBe("please and reply");
  });

  test("inline /model with an unresolvable shorthand never mutates config and logs the resolver error", () => {
    // This is the "what happens if the arg is wrong" path. The resolver
    // throws — applyInline... must swallow the throw, leave config.model
    // intact, and surface the resolver's exact message under [model] so
    // the user sees what went wrong instead of a silent swap.
    const config = makeConfig();
    const log = makeLog();

    const { residue } = applyInlineSlashCommandsToCliConfig(
      "hey /model totally-not-a-real-model please review this",
      config,
      log.write,
    );

    expect(config.model).toBe("anthropic:claude-opus-4-7");
    const joined = log.lines.join("");
    expect(joined).toMatch(/\[model\]/);
    expect(joined).toMatch(/totally-not-a-real-model/);
    // No success confirmation should have been written.
    expect(joined).not.toMatch(/next turn will use/);
    // Even though validation failed, the slash form is still stripped
    // from the residue — the parser already committed to treating
    // `totally-not-a-real-model` as the arg, so leaving it in would be
    // worse (the agent would see a half-mangled prompt).
    expect(residue).toBe("hey please review this");
  });

  test("inline /thinking with an unknown level never mutates config and lists the legal values", () => {
    const config = makeConfig({ thinkingLevel: "medium" });
    const log = makeLog();

    const { residue } = applyInlineSlashCommandsToCliConfig(
      "/thinking ultra please go",
      config,
      log.write,
    );

    expect(config.thinkingLevel).toBe("medium");
    const joined = log.lines.join("");
    expect(joined).toContain("[thinking] Unknown thinking level: ultra");
    expect(joined).toContain("minimal, low, medium, high, xhigh");
    expect(joined).not.toMatch(/next turn will think at/);
    expect(residue).toBe("please go");
  });

  test("trailing /model with no following token is left in the residue (token shape requires an arg)", () => {
    // The token-shape inline pattern requires `[ \t]+(\S+)` after the
    // command name. With nothing following, there is no match, so the
    // slash form is not stripped and falls through to the agent.
    const config = makeConfig();
    const log = makeLog();

    const { residue } = applyInlineSlashCommandsToCliConfig(
      "please look at this and /model",
      config,
      log.write,
    );

    expect(config.model).toBe("anthropic:claude-opus-4-7");
    expect(log.lines).toEqual([]);
    expect(residue).toBe("please look at this and /model");
  });

  test("a bad /model followed by a good /thinking still applies the /thinking swap", () => {
    // Each inline command is independent: a validation failure on one
    // must not stop the loop from applying the others.
    const config = makeConfig({ thinkingLevel: "medium" });
    const log = makeLog();

    const { residue } = applyInlineSlashCommandsToCliConfig(
      "hey /model totally-not-real and /thinking high please",
      config,
      log.write,
    );

    expect(config.model).toBe("anthropic:claude-opus-4-7");
    expect(config.thinkingLevel).toBe("high");
    const joined = log.lines.join("");
    expect(joined).toContain("[model]");
    expect(joined).toContain("[thinking] next turn will think at high");
    expect(residue).toBe("hey and please");
  });
});

