      source: "explicit",
    });
    expect(memoryModelResolution).toEqual({
      modelName: "haiku-4.5",
      source: "explicit",
    });
  });

  test("builds CLI config from inferred shorthand defaults", () => {
    clearModelEnv();
    process.env.OPENAI_API_KEY = "test-openai";

    const { config, modelResolution, memoryModelResolution } = buildCliTurnConfig(
