    });
    expect(modelResolution).toEqual({
      modelName: "gpt-5.5",
      source: "inferred",
      envVar: "OPENAI_API_KEY",
      fromDotenv: false,
    });
    expect(memoryModelResolution).toEqual({
      modelName: "gpt-5.4-mini",
      source: "inferred",
      envVar: "OPENAI_API_KEY",
      fromDotenv: false,
    });
  });
});

